      break
    case 'article':
      page = Content
        ? renderArticlePage(data.manifest, data.route, Content)
        : <div>Loading...</div>
      break
    case 'books':
      page = renderHomePage(data.manifest)
      break
    case 'articles':
      page = renderHomePage(data.manifest)
      break
    default:
      page = <div>Page not found</div>
  }

  render(page, document.getElementById('app')!)
}

