      {manifest.books.length > 0 && (
        <section class="pressy-home-section">
          <h2>Books</h2>
          <nav class="pressy-chapter-list">
            {manifest.books.map((book: Book) => (
              <a
                href={`${basePath}/books/${book.slug}`}
                class="pressy-chapter-link"
              >
