import * as preact from 'preact';
import { ComponentType, ComponentChildren } from 'preact';

interface ProgressData {
    page: number;
    totalPages: number;
    scrollPosition: number;
    /** In multi-chapter mode, the slug of the chapter this progress belongs to. */
    activeChapterSlug?: string;
}
interface ChapterMapData {
    chapterMap: Record<string, () => Promise<{
        default: ComponentType<{
            components?: Record<string, unknown>;
        }>;
    }>>;
    chapterOrder: string[];
}
interface OfflineProps {
    bookSlug: string;
    chapterUrls: string[];
    cachedBooks: {
        value: Set<string>;
    };
    cacheProgress: {
        value: {
            bookSlug: string;
            current: number;
            total: number;
        } | null;
    };
    onDownload: (bookSlug: string, chapterUrls: string[]) => void;
    onRemove: (bookSlug: string) => void;
}
interface ReaderProps {
    children: ComponentChildren;
    title: string;
    bookTitle?: string;
    chapterSlug?: string;
    prevChapter?: {
        slug: string;
        title: string;
    };
    nextChapter?: {
        slug: string;
        title: string;
    };
    showDropCap?: boolean;
    paginationMode?: "scroll" | "paginated";
    onSaveProgress?: (data: ProgressData) => void;
    onRestoreProgress?: () => Promise<ProgressData | null>;
    bookProgressPercent?: number;
    initialContent?: ComponentType<{
        components?: Record<string, unknown>;
    }>;
    chapterMapData?: ChapterMapData;
    currentChapterSlug?: string;
    allChapters?: Array<{
        slug: string;
        title: string;
        wordCount?: number;
    }>;
    bookBasePath?: string;
    onChapterChange?: (slug: string, page: number, totalPages: number) => void;
    mdxComponents?: Record<string, unknown>;
    offlineProps?: OfflineProps;
}
declare function Reader({ children, bookTitle, prevChapter, nextChapter, showDropCap, paginationMode, onSaveProgress, onRestoreProgress, bookProgressPercent, initialContent, chapterMapData, currentChapterSlug, allChapters, bookBasePath, onChapterChange, mdxComponents, offlineProps, }: ReaderProps): preact.JSX.Element;

interface NavigationProps {
    prev?: {
        slug: string;
        title: string;
    };
    next?: {
        slug: string;
        title: string;
    };
}
declare function Navigation({ prev, next }: NavigationProps): preact.JSX.Element | null;

interface TOCItem {
    level: number;
    text: string;
    slug: string;
}
interface TableOfContentsProps {
    items: TOCItem[];
    onNavigate?: () => void;
    activeSlug?: string;
}
declare function TableOfContents({ items, onNavigate, activeSlug }: TableOfContentsProps): preact.JSX.Element;

declare function TextShare(): preact.JSX.Element | null;

interface PaywallProps {
    bookSlug: string;
    bookTitle: string;
    previewChapters: number;
    currentChapter: number;
    shopifyProductId?: string;
    mode?: 'shopify' | 'email';
    onUnlock?: () => void;
}
declare function Paywall({ bookSlug, bookTitle, previewChapters, currentChapter, shopifyProductId, mode, onUnlock, }: PaywallProps): preact.JSX.Element | null;

declare function ThemeSwitcher(): preact.JSX.Element;

declare function OfflineIndicator(): preact.JSX.Element | null;

interface DownloadBookProps {
    bookSlug: string;
    chapterUrls: string[];
    /** Reactive signal: set of cached book slugs */
    cachedBooks: {
        value: Set<string>;
    };
    /** Reactive signal: current download progress or null */
    cacheProgress: {
        value: {
            bookSlug: string;
            current: number;
            total: number;
        } | null;
    };
    /** Called to start downloading the book */
    onDownload: (bookSlug: string, chapterUrls: string[]) => void;
    /** Called to remove the cached book */
    onRemove: (bookSlug: string) => void;
}
declare function DownloadBook({ bookSlug, chapterUrls, cachedBooks, cacheProgress, onDownload, onRemove, }: DownloadBookProps): preact.JSX.Element;

interface BookProgressProps {
    bookSlug: string;
    chapters: Array<{
        slug: string;
        title: string;
        order: number;
        wordCount?: number;
    }>;
    basePath: string;
    loadAllProgress: () => Promise<Array<{
        chapterSlug: string;
        page: number;
        totalPages: number;
    }>>;
}
declare function BookProgress({ chapters, basePath, bookSlug, loadAllProgress, }: BookProgressProps): preact.JSX.Element;

export { BookProgress, type BookProgressProps, type ChapterMapData, DownloadBook, type DownloadBookProps, Navigation, type NavigationProps, OfflineIndicator, type OfflineProps, Paywall, type PaywallProps, type ProgressData, Reader, type ReaderProps, type TOCItem, TableOfContents, type TableOfContentsProps, TextShare, ThemeSwitcher };

