const handleSaveProgress = (data: ProgressData) => {
  // In multi-chapter mode, PaginatedReader tells us which chapter the
  // progress belongs to (the user may have scrolled past the initial URL chapter).
  const saveSlug = data.activeChapterSlug || chapterSlug

  saveReadingProgress({
    chapterSlug: saveSlug,
    page: data.page,
    totalPages: data.totalPages,
    scrollPosition: data.scrollPosition,
    timestamp: Date.now(),
  })

  // localStorage is synchronous and survives page close/refresh,
  // unlike IndexedDB which is async and may not flush in time.
  // Include page info so we can restore position even if IndexedDB is stale.
  localStorage.setItem('pressy-last-read', JSON.stringify({
    bookSlug: book.slug, chapterSlug: saveSlug,
    page: data.page, totalPages: data.totalPages,
  }))

  // Update global book progress with live page position
  if (data.totalPages > 0) {
    getAllReadingProgress().then((allProgress) => {
      const percent = calculateBookProgressPercent(
        book, saveSlug, data.page, data.totalPages, allProgress,
      )
      setBookProgressPercent(percent)
    })
  }
}

const handleRestoreProgress = async (): Promise<ProgressData | null> => {
  // Try IndexedDB first (has full history for all chapters)
  const progress = await getReadingProgress(chapterSlug)
  if (progress && progress.page > 0) {
    return {
      page: progress.page,
      totalPages: progress.totalPages,
      scrollPosition: progress.scrollPosition,
    }
  }

  // Fall back to localStorage for the last-read chapter.
  // IndexedDB writes are async and may not have flushed before
  // page close/refresh, but localStorage writes are synchronous.
  try {
    const lastRead = localStorage.getItem('pressy-last-read')
    if (lastRead) {
      const parsed = JSON.parse(lastRead)
      if (parsed.chapterSlug === chapterSlug && parsed.page > 0) {
        return { page: parsed.page, totalPages: parsed.totalPages, scrollPosition: 0 }
      }
    }
  } catch {
    // ignore
  }

  return progress ? {
    page: progress.page,
    totalPages: progress.totalPages,
    scrollPosition: progress.scrollPosition,
  } : null
}

